import{_ as a,o as d,c as e,ag as l}from"./chunks/framework.CNG7EpJN.js";const b=JSON.parse('{"title":"障害報告窓口とお問い合わせコード","description":"","frontmatter":{"title":"障害報告窓口とお問い合わせコード","audience":"店舗オーナー / 店長 / POSLA利用スタッフ","last_updated":"2026-04-27T00:00:00.000Z"},"headers":[],"relativePath":"tenant/27-incident-report.md","filePath":"tenant/27-incident-report.md"}'),i={name:"tenant/27-incident-report.md"};function s(n,t,r,p,o,h){return d(),e("div",null,[...t[0]||(t[0]=[l(`<h1 id="_27-障害報告窓口とお問い合わせコード" tabindex="-1">27. 障害報告窓口とお問い合わせコード <a class="header-anchor" href="#_27-障害報告窓口とお問い合わせコード" aria-label="Permalink to &quot;27. 障害報告窓口とお問い合わせコード&quot;">​</a></h1><p>POSLAで注文、会計、予約、KDS、ログインなどに問題が出た場合は、画面に表示された <strong>お問い合わせコード</strong> と発生状況を POSLA 運営へ共有してください。</p><div class="tip custom-block"><p class="custom-block-title">最初に伝えるもの</p><ul><li>店舗名</li><li>画面名</li><li>表示されたお問い合わせコード</li><li>発生時刻</li><li>何をしようとしたか</li><li>可能であればスクリーンショット</li></ul></div><h2 id="_27-1-障害報告窓口の役割" tabindex="-1">27.1 障害報告窓口の役割 <a class="header-anchor" href="#_27-1-障害報告窓口の役割" aria-label="Permalink to &quot;27.1 障害報告窓口の役割&quot;">​</a></h2><p>障害報告窓口は、POSLAの操作中に起きた不具合や業務停止に近い問題を報告するための窓口です。</p><p>対象になるもの:</p><table tabindex="0"><thead><tr><th>対象</th><th>例</th></tr></thead><tbody><tr><td>レジ / 会計</td><td>会計できない、決済が途中で止まる、レシートが出ない</td></tr><tr><td>注文</td><td>注文がKDSへ出ない、注文履歴に残らない</td></tr><tr><td>KDS</td><td>厨房画面が更新されない、調理ステータス変更ができない</td></tr><tr><td>予約</td><td>予約台帳に入らない、予約通知が届かない</td></tr><tr><td>ログイン</td><td>正しいID/パスワードでも入れない</td></tr><tr><td>画面エラー</td><td><code>E3035</code> のようなお問い合わせコードが出る</td></tr></tbody></table><p>対象外のもの:</p><table tabindex="0"><thead><tr><th>対象外</th><th>連絡方法</th></tr></thead><tbody><tr><td>使い方の質問</td><td>サポートガイド、通常のお問い合わせ</td></tr><tr><td>新機能の要望</td><td>POSLA運営への要望連絡</td></tr><tr><td>契約・請求の相談</td><td>契約窓口</td></tr><tr><td>店舗内のWi-Fiや端末故障</td><td>店舗側のネットワーク・端末確認</td></tr></tbody></table><h2 id="_27-2-お問い合わせコードとは" tabindex="-1">27.2 お問い合わせコードとは <a class="header-anchor" href="#_27-2-お問い合わせコードとは" aria-label="Permalink to &quot;27.2 お問い合わせコードとは&quot;">​</a></h2><p>POSLAのエラーには、原因調査を早くするための番号が付くことがあります。</p><p>例:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>処理に失敗しました</span></span>
<span class="line"><span>お問い合わせコード: E3035</span></span>
<span class="line"><span>発生時刻: 2026-04-27 10:15</span></span></code></pre></div><p>この番号があると、POSLA運営側で該当エラー、関連API、直近のログ、対象店舗、対象cellを確認しやすくなります。</p><h2 id="_27-3-報告時に必要な情報" tabindex="-1">27.3 報告時に必要な情報 <a class="header-anchor" href="#_27-3-報告時に必要な情報" aria-label="Permalink to &quot;27.3 報告時に必要な情報&quot;">​</a></h2><p>障害報告では、できるだけ次を入力してください。</p><table tabindex="0"><thead><tr><th>項目</th><th>例</th><th>理由</th></tr></thead><tbody><tr><td>お問い合わせコード</td><td><code>E3035</code></td><td>原因候補を絞るため</td></tr><tr><td>画面名</td><td>POSレジ、KDS、予約台帳</td><td>関連機能を特定するため</td></tr><tr><td>店舗名</td><td>渋谷店</td><td>複数店舗運用で対象を間違えないため</td></tr><tr><td>発生時刻</td><td>2026-04-27 18:30頃</td><td>ログ確認範囲を絞るため</td></tr><tr><td>操作内容</td><td>現金会計を確定しようとした</td><td>再現手順を確認するため</td></tr><tr><td>支払い方法</td><td>現金、カード、QR</td><td>決済系の切り分けに必要</td></tr><tr><td>スクリーンショット</td><td>画面全体</td><td>表示文言の取り違えを防ぐため</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">コードと画面が合わない場合があります</p><p>お問い合わせコードだけで判断できないことがあります。 たとえば「レジで会計できない」と申告されても、コードが予約AIのエラーを示している場合は、まず実際の画面とコードの取り違えを確認します。</p></div><h2 id="_27-4-緊急度の目安" tabindex="-1">27.4 緊急度の目安 <a class="header-anchor" href="#_27-4-緊急度の目安" aria-label="Permalink to &quot;27.4 緊急度の目安&quot;">​</a></h2><table tabindex="0"><thead><tr><th>緊急度</th><th>状況</th><th>店舗側の初動</th></tr></thead><tbody><tr><td>高</td><td>会計できない、注文が通らない、レジが止まる</td><td>代替運用へ切替し、すぐ報告</td></tr><tr><td>中</td><td>一部機能だけ使えない、特定店舗だけ発生</td><td>店長が状況を整理して報告</td></tr><tr><td>低</td><td>表示が遅い、再読み込みで直る、単発エラー</td><td>再発するか確認してから報告</td></tr></tbody></table><p>営業中に会計や注文が止まる場合は、まず店舗の営業継続を優先します。</p><ul><li>紙伝票で注文を控える</li><li>手書きで会計を控える</li><li>決済端末やレジが使えない場合は店舗ルールに従う</li><li>復旧後にPOSLAへ入力し直す必要がある内容を残す</li></ul><h2 id="_27-5-posla運営側で行うこと" tabindex="-1">27.5 POSLA運営側で行うこと <a class="header-anchor" href="#_27-5-posla運営側で行うこと" aria-label="Permalink to &quot;27.5 POSLA運営側で行うこと&quot;">​</a></h2><p>障害報告が送信されると、POSLA運営側では次を確認します。</p><ol><li>対象の顧客名、cell、店舗を特定</li><li>お問い合わせコードの意味を確認</li><li>直近のエラーログ、監視イベント、デプロイ履歴を確認</li><li>必要に応じてAI運用支援基盤で調査</li><li>コード修正、設定修正、顧客への確認依頼のどれが必要か判断</li></ol><p>店舗側は、調査のために追加情報を求められる場合があります。</p><h2 id="_27-6-送ってはいけない情報" tabindex="-1">27.6 送ってはいけない情報 <a class="header-anchor" href="#_27-6-送ってはいけない情報" aria-label="Permalink to &quot;27.6 送ってはいけない情報&quot;">​</a></h2><p>障害報告には、次の情報を入力しないでください。</p><ul><li>クレジットカード番号</li><li>セキュリティコード</li><li>お客様の不要な個人情報</li><li>POSLA以外のサービスのパスワード</li><li>店舗Wi-Fiのパスワード</li></ul><p>必要な場合でも、POSLA運営から案内された安全な方法で共有してください。</p><h2 id="_27-7-よくある報告例" tabindex="-1">27.7 よくある報告例 <a class="header-anchor" href="#_27-7-よくある報告例" aria-label="Permalink to &quot;27.7 よくある報告例&quot;">​</a></h2><h3 id="良い例" tabindex="-1">良い例 <a class="header-anchor" href="#良い例" aria-label="Permalink to &quot;良い例&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>店舗: 渋谷店</span></span>
<span class="line"><span>画面: POSレジ</span></span>
<span class="line"><span>お問い合わせコード: E3035</span></span>
<span class="line"><span>発生時刻: 2026-04-27 18:32</span></span>
<span class="line"><span>内容: 現金会計で確定ボタンを押したところ、エラーが出て会計完了になりません。</span></span>
<span class="line"><span>補足: 同じ端末で2回発生。別端末では未確認。スクリーンショットあり。</span></span></code></pre></div><h3 id="情報が不足している例" tabindex="-1">情報が不足している例 <a class="header-anchor" href="#情報が不足している例" aria-label="Permalink to &quot;情報が不足している例&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>レジが動きません。</span></span></code></pre></div><p>この場合、画面、コード、時刻、支払い方法がないため、原因調査に時間がかかります。</p><h2 id="_27-8-復旧後に確認すること" tabindex="-1">27.8 復旧後に確認すること <a class="header-anchor" href="#_27-8-復旧後に確認すること" aria-label="Permalink to &quot;27.8 復旧後に確認すること&quot;">​</a></h2><p>POSLA運営から復旧連絡を受けたら、店舗側で次を確認してください。</p><ol><li>同じ操作をもう一度実行できるか</li><li>注文・会計・予約などのデータが重複していないか</li><li>レシート、レポート、売上が想定通りか</li><li>代替運用で控えた内容をPOSLAに反映する必要があるか</li></ol><p>復旧後も同じお問い合わせコードが出る場合は、同じ報告に追記するか、再度障害報告を送信してください。</p>`,40)])])}const u=a(i,[["render",s]]);export{b as __pageData,u as default};
